// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State for multi-step form
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  // Helper: email validation
  const isValidEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };
  // Helper: validate required fields for current step
  const validateStep = (step: number): boolean => {
    const newErrors: Record<string, string> = {};
    if (step === 1) {
      if (!formData.name.trim()) {
        newErrors.name = 'Name is required';
      }
      if (!formData.email.trim()) {
        newErrors.email = 'Email is required';
      } else if (!isValidEmail(formData.email)) {
        newErrors.email = 'Please enter a valid email address';
      }
    } else if (step === 2) {
      if (formData.satisfaction === 0) {
        newErrors.satisfaction = 'Please select a satisfaction rating';
      }
    } else if (step === 3) {
      if (formData.features.length === 0) {
        newErrors.features = 'Please select at least one feature';
      }
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };
  // Helper: check if current step is valid for Next button
  const isStepValid = (): boolean => {
    if (currentStep === 1) {
      return (formData.name.trim() !== '' && 
              formData.email.trim() !== '' && 
              isValidEmail(formData.email));
    } else if (currentStep === 2) {
      return formData.satisfaction > 0;
    } else if (currentStep === 3) {
      return formData.features.length > 0;
    } else if (currentStep === 4) {
      return true; // Comments are optional
    } else if (currentStep === 5) {
      return true; // Review step
    }
    return false;
  };
  // Handlers
  const handleNext = () => {
    if (validateStep(currentStep)) {
      if (currentStep === 4) {
        setCurrentStep(5); // Move to review
      } else if (currentStep < 4) {
        setCurrentStep(currentStep + 1);
      }
    }
  };
  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };
  const handleSubmit = () => {
    submit({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments,
    });
  };
  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label: `${index + 1} - ${label}`,
  }));
  const featureCheckboxes = props.featureOptions.map((feature) => ({
    value: feature,
    label: feature,
  }));
  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="center">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)" align="center">
          <Heading level={2}>Multi-Step Survey</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Step {currentStep} of 4
          </Text>
        </Stack>
        {/* Progress Bar */}
        <Progress value={currentStep} max={4} variant="default" size="md" />
        {/* Step Content */}
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg" style={{ width: '100%', maxWidth: '600px' }}>
          {/* Step 1: Name & Email */}
          {currentStep === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Contact Information</Heading>
              <Input
                label="Full Name"
                placeholder="John Doe"
                value={formData.name}
                onChange={(value) => {
                  setFormData({ ...formData, name: value });
                  if (errors.name) setErrors({ ...errors, name: '' });
                }}
                error={errors.name}
                required
              />
              <Input
                label="Email Address"
                type="email"
                placeholder="john@example.com"
                value={formData.email}
                onChange={(value) => {
                  setFormData({ ...formData, email: value });
                  if (errors.email) setErrors({ ...errors, email: '' });
                }}
                error={errors.email}
                required
              />
            </Stack>
          )}
          {/* Step 2: Satisfaction Rating */}
          {currentStep === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>How Satisfied Are You?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={String(formData.satisfaction)}
                onChange={(value) => {
                  setFormData({ ...formData, satisfaction: parseInt(value) });
                  if (errors.satisfaction) setErrors({ ...errors, satisfaction: '' });
                }}
                options={satisfactionOptions}
                direction="vertical"
                error={errors.satisfaction}
              />
            </Stack>
          )}
          {/* Step 3: Feature Interests */}
          {currentStep === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Which Features Interest You?</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Select at least one feature
              </Text>
              <Stack gap="var(--ggui-spacing-2)">
                {featureCheckboxes.map((feature) => (
                  <Checkbox
                    key={feature.value}
                    label={feature.label}
                    checked={formData.features.includes(feature.value)}
                    onChange={(checked) => {
                      setFormData({
                        ...formData,
                        features: checked
                          ? [...formData.features, feature.value]
                          : formData.features.filter((f) => f !== feature.value),
                      });
                      if (errors.features) setErrors({ ...errors, features: '' });
                    }}
                  />
                ))}
              </Stack>
              {errors.features && (
                <Text variant="caption" color="var(--ggui-color-error-600)">
                  {errors.features}
                </Text>
              )}
            </Stack>
          )}
          {/* Step 4: Comments */}
          {currentStep === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Additional Comments</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Feel free to share any additional feedback (optional)
              </Text>
              <TextArea
                label="Comments"
                placeholder="Your feedback here..."
                value={formData.comments}
                onChange={(value) => {
                  if (value.length <= 500) {
                    setFormData({ ...formData, comments: value });
                  }
                }}
                rows={5}
                maxLength={500}
                showCount
              />
            </Stack>
          )}
          {/* Step 5: Review */}
           {currentStep === 5 && (
             <Stack gap="var(--ggui-spacing-4)">
               <Heading level={3}>Review Your Answers</Heading>
               <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="md">
                 <Stack gap="var(--ggui-spacing-4)">
                    <Box padding="var(--ggui-spacing-3)" style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                      <Text variant="body">{formData.name}</Text>
                    </Box>
                    <Box padding="var(--ggui-spacing-3)" style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                      <Text variant="body">{formData.email}</Text>
                    </Box>
                    <Box padding="var(--ggui-spacing-3)" style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction Rating</Text>
                      <Text variant="body">
                        {formData.satisfaction > 0 && formData.satisfaction <= props.satisfactionLabels.length
                          ? `${formData.satisfaction} - ${props.satisfactionLabels[formData.satisfaction - 1]}`
                          : 'Not selected'}
                      </Text>
                    </Box>
                    <Box padding="var(--ggui-spacing-3)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Features of Interest</Text>
                      <Stack gap="var(--ggui-spacing-1)" style={{ marginTop: 'var(--ggui-spacing-2)' }}>
                        {formData.features.length > 0 ? (
                          formData.features.map((feature) => (
                            <Badge key={feature} variant="primary">
                              {feature}
                            </Badge>
                          ))
                        ) : (
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">None selected</Text>
                        )}
                      </Stack>
                    </Box>
                    <Box padding="var(--ggui-spacing-3)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments</Text>
                      <Text variant="body">{formData.comments || '(None provided)'}</Text>
                    </Box>
                  </Stack>
                </Card>
              </Stack>
            )}
           {/* Navigation Buttons */}
           <Row gap="var(--ggui-spacing-3)" justify="center">
             <Button
               variant="outline"
               onClick={handleBack}
               disabled={currentStep === 1}
             >
               Back
             </Button>
             {currentStep < 5 && (
               <Button
                 variant="primary"
                 onClick={handleNext}
                 disabled={!isStepValid()}
               >
                 Next
               </Button>
             )}
             {currentStep === 5 && (
               <Button
                 variant="primary"
                 onClick={handleSubmit}
               >
                 Submit
               </Button>
             )}
           </Row>
         </Card>
       </Stack>
     </Container>
  }

