export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // Local state for tasks
  const [tasks, setTasks] = useState(props.tasks);

  // Update local tasks when props change
  useEffect(() => {
    setTasks(props.tasks);
  }, [props.tasks]);

  // Listen for stream updates from other users
  useEffect(() => {
    if (taskChanged.latest?.task) {
      const updatedTask = taskChanged.latest.task;
      setTasks(prev => {
        const existing = prev.findIndex(t => t.id === updatedTask.id);
        if (existing >= 0) {
          const newTasks = [...prev];
          newTasks[existing] = { ...newTasks[existing], ...updatedTask };
          return newTasks;
        }
        return [...prev, updatedTask];
      });
    }
  }, [taskChanged.latest]);

  // Handle task move
  const handleMoveTask = useCallback((taskId: string, toColumn: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: toColumn } : t));
    taskUpdate({ action: 'move', taskId, data: { column: toColumn } });
  }, [taskUpdate]);

  // Handle task edit
  const handleEditTask = useCallback((taskId: string, title: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, title } : t));
    taskUpdate({ action: 'edit', taskId, data: { column: tasks.find(t => t.id === taskId)?.column || 'todo' } });
  }, [taskUpdate, tasks]);

  // Handle task creation
  const handleAddTask = useCallback((columnId: string, title: string, priority: 'low' | 'medium' | 'high') => {
    const newTask = {
      id: `task-${Date.now()}`,
      title,
      priority,
      column: columnId,
    };
    setTasks(prev => [...prev, newTask]);
    taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
  }, [taskUpdate]);

  // Calculate stats
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(t => t.column === 'done').length;

  // Group tasks by column
  const tasksByColumn = useMemo(() => {
    return props.columns.map(col => ({
      column: col,
      tasks: tasks.filter(t => t.column === col.id),
    }));
  }, [tasks, props.columns]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Kanban Board</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            {completedTasks} of {totalTasks} tasks completed
          </Text>
          <Progress value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0} max={100} variant="success" size="md" />
        </Stack>

        {/* Kanban columns */}
        <Row gap="var(--ggui-spacing-4)" align="start" wrap={true}>
          {tasksByColumn.map(({ column, tasks: columnTasks }) => (
            <Box key={column.id} flex={1} minWidth="320px">
              <KanbanColumn
                column={column}
                tasks={columnTasks}
                allColumns={props.columns}
                onMove={handleMoveTask}
                onEdit={handleEditTask}
                onAddTask={(title, priority) => handleAddTask(column.id || 'todo', title, priority)}
              />
            </Box>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}
}

