  const specifications = Array.isArray(props.product.specifications) ? props.product.specifications : [];
  const reviews = Array.isArray(props.product.reviews) ? props.product.reviews : [];

  // Format price with currency
  const currencySymbols: Record<string, string> = {
    USD: '$',
    EUR: '€',
    GBP: '£',
    JPY: '¥',
  };
  const symbol = currencySymbols[currency] ?? currency;
  const formattedPrice = `${symbol}${price.toFixed(2)}`;

  // Determine stock status
  const isInStock = stock > 0;
  const isLowStock = stock > 0 && stock <= 5;
  const stockStatus = isInStock ? (isLowStock ? 'Low Stock' : 'In Stock') : 'Out of Stock';
  const stockVariant = isInStock ? (isLowStock ? 'warning' : 'success') : 'error';

  // Rating stars renderer
  const renderStars = (ratingValue: number) => {
    const stars = [];
    for (let i = 1; i <= 5; i++) {
      const filled = i <= Math.round(ratingValue);
      stars.push(
        <Icon
          key={i}
          name="star"
          size={16}
          color={filled ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outlineVariant)'}
        />
      );
    }
    return stars;
  };

  // Increment/decrement handlers
  const handleDecrement = useCallback(() => {
    setQuantity((prev) => Math.max(1, prev - 1));
  }, []);

  const handleIncrement = useCallback(() => {
    setQuantity((prev) => Math.min(stock, prev + 1));
  }, [stock]);

  // Add to cart handler
  const handleAddToCart = useCallback(() => {
    addToCart({ productId, quantity });
  }, [productId, quantity, addToCart]);

  // Format date for reviews
  const formatDate = (date: unknown): string => {
    if (typeof date === 'string') {
      return new Date(date).toLocaleDateString();
    }
    if (date instanceof Date) {
      return date.toLocaleDateString();
    }
    return 'Unknown date';
  };

