  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // Local state for messages and input
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [inputValue, setInputValue] = useState('');
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages(prev => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator
  useEffect(() => {
    if (typing.latest) {
      setTypingUsers(prev => {
        const next = new Set(prev);
        if (typing.latest!.active) {
          next.add(typing.latest!.sender || 'Unknown');
        } else {
          next.delete(typing.latest!.sender || 'Unknown');
        }
        return next;
      });
    }
  }, [typing.latest]);

  // Auto-scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages]);

  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      sendMessage({ text: inputValue, timestamp: new Date().toISOString() });
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)" style={{ height: '100vh', display: 'flex', flexDirection: 'column' }}>
        {/* Header */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row justify="between" align="center">
            <Stack direction="horizontal" gap="var(--ggui-spacing-3)" align="center">
              <Heading level={3}>{props.title}</Heading>
              <Badge variant="primary" size="sm">
                {props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}
              </Badge>
            </Stack>
            {typingUsers.size > 0 && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {Array.from(typingUsers).join(', ')} {typingUsers.size === 1 ? 'is' : 'are'} typing...
              </Text>
            )}
          </Row>
        </Card>

        {/* Message List */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm" style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-3)' }}>
          {allMessages.length === 0 ? (
            <Text align="center" color="var(--ggui-color-onSurfaceVariant)">No messages yet. Start the conversation!</Text>
          ) : (
            allMessages.map((msg, idx) => {
              const isCurrentUser = msg.sender === props.currentUser;
              const showSender = idx === 0 || (allMessages[idx - 1] && allMessages[idx - 1].sender !== msg.sender);
              return (
                <Stack key={idx} gap="var(--ggui-spacing-1)">
                  {showSender && (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      {msg.sender || 'Unknown'}
                    </Text>
                  )}
                  <Box
                    padding="var(--ggui-spacing-3)"
                    background={isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                    borderRadius="var(--ggui-shape-radius-md)"
                    style={{
                      alignSelf: isCurrentUser ? 'flex-end' : 'flex-start',
                      maxWidth: '70%',
                    }}
                  >
                    <Text
                      color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurface)'}
                      variant="body"
                    >
                       {msg.text || '(empty message)'}
                    </Text>
                    {msg.timestamp && (
                      <Text
                        variant="caption"
                        color={isCurrentUser ? 'var(--ggui-color-primary-200)' : 'var(--ggui-color-onSurfaceVariant)'}
                        style={{ marginTop: 'var(--ggui-spacing-1)' }}
                      >
                        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </Text>
                    )}
                  </Box>
                </Stack>
              );
            })
          )}
          <div ref={messagesEndRef} />
        </Card>

        {/* Input Area */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
          <Input
            label="Message"
            placeholder="Type your message..."
            value={inputValue}
            onChange={setInputValue}
            onKeyDown={handleKeyDown}
            style={{ flex: 1 }}
          />
          <Button
            variant="primary"
            onClick={handleSendMessage}
            disabled={!inputValue.trim()}
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

