// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for merged stock data
  const [displayStocks, setDisplayStocks] = useState(props.stocks);

  // Track last update timestamp for the "Last Updated" display
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());

  // Track which stocks just updated for animation triggering
  const [updatedStocks, setUpdatedStocks] = useState<Set<string>>(new Set());

  // Memoize animation keys for each stock price to enable flash animation
  const animationKeys = useMemo(() => {
    const keys: Record<string, number> = {};
    displayStocks.forEach(stock => {
      keys[stock.symbol || ''] = (keys[stock.symbol || ''] || 0) + 1;
    });
    return keys;
  }, [displayStocks.map(s => `${s.symbol}-${s.price}`).join('|')]);

  // Merge price updates into displayed stocks
  // Merge price updates into displayed stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      setDisplayStocks(prev => {
        const updated = prev.map(stock => {
          if (stock.symbol === priceUpdate.latest?.symbol) {
            setUpdatedStocks(s => new Set(s).add(stock.symbol || ''));
            return {
              ...stock,
              price: priceUpdate.latest?.price ?? stock.price,
              change: priceUpdate.latest?.change ?? stock.change,
              changePercent: priceUpdate.latest?.changePercent ?? stock.changePercent,
            };
          }
          return stock;
        });
        return updated;
      });
      setLastUpdated(new Date());
      // Clear the animation marker after a short delay so next update triggers animation again
      setTimeout(() => setUpdatedStocks(new Set()), 600);
    }
  }, [priceUpdate.latest]);

  return (
