         <CardGrid columns={{ sm: 1, md: 3 }} gap={parseInt('var(--ggui-spacing-4)') || 16}>
           {displayStocks && displayStocks.length > 0 ? (
             displayStocks.map((stock) => {
               const isPositive = (stock.changePercent ?? 0) >= 0;
               const borderColor = isPositive
                 ? 'var(--ggui-color-success-500)'
                 : 'var(--ggui-color-error-500)';
               const textColor = isPositive
                 ? 'var(--ggui-color-success-600)'
                 : 'var(--ggui-color-error-600)';
               const priceKey = animationKeys[stock.symbol || ''];
               const wasJustUpdated = updatedStocks.has(stock.symbol || '');
              return (
                <Card
                  key={stock.symbol}
                  as={Hoverable}
                  hoverStyle={{ opacity: 0.85, boxShadow: 'var(--ggui-shape-shadow-lg)' }}
                  padding="var(--ggui-spacing-4)"
                  shadow="md"
                  border
