                  aria-label={`${stock.symbol} stock ticker: ${stock.name}`}
                  style={{
                    borderColor,
                    borderWidth: '2px',
                    transition: 'all 200ms ease-in-out',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-3)">
                    {/* Ticker symbol */}
                    <Heading level={3} color={textColor}>
                      {stock.symbol}
                    </Heading>

                    {/* Company name */}
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                      {stock.name}
                    </Text>

                    {/* Current price with flash animation on update */}
                    <Heading
                      level={4}
                      key={priceKey}
                      style={wasJustUpdated ? {
                        animation: animation.flash,
                        '--ggui-flash-color': isPositive
                          ? 'var(--ggui-color-success-100)'
                          : 'var(--ggui-color-error-100)',
                      } as React.CSSProperties : undefined}
                    >
                      ${stock.price?.toFixed(2) ?? '0.00'}
                    </Heading>

                    {/* Change amount and percentage with arrow */}
                    <Row gap="var(--ggui-spacing-2)" align="center">
                      <Icon
                        name={isPositive ? 'arrow-up' : 'arrow-down'}
                        size={16}
                        color={textColor}
                        aria-label={isPositive ? 'price increased' : 'price decreased'}
                      />
                      <Text variant="body" color={textColor}>
                        {isPositive ? '+' : ''}{stock.change?.toFixed(2) ?? '0.00'}
                      </Text>
                      <Text variant="label" color={textColor}>
                        ({isPositive ? '+' : ''}{stock.changePercent?.toFixed(2) ?? '0.00'}%)
                      </Text>
                    </Row>
                  </Stack>
                </Card>
              );
            })
          ) : (
            <Text color="var(--ggui-color-onSurfaceVariant)">No stocks to display</Text>
          )}
        </CardGrid>
      </Stack>
    </Container>
  );
