}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touchedName, setTouchedName] = useState(false);
  const [touchedEmail, setTouchedEmail] = useState(false);

  const maxComments = 500;
  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = touchedName && name.trim().length === 0 ? 'Name is required.' : '';
  const emailError = touchedEmail && email.trim().length === 0 ? 'Email is required.' : touchedEmail && !emailValid ? 'Please enter a valid email address.' : '';

  const satisfactionOptions = useMemo(
    () =>
      [1, 2, 3, 4, 5].map((value) => ({
        value: String(value),
        label: (props.satisfactionLabels || [])[value - 1] || `Rating ${value}`,
      })),
    [props.satisfactionLabels],
  );


  const canNext = useMemo(() => {
    if (step === 1) {
      return name.trim().length > 0 && emailValid;
    }
    if (step === 2) {
      return satisfaction !== '';
    }
    return true;
  }, [step, name, emailValid, satisfaction]);

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        return prev.includes(feature) ? prev : [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const goNext = useCallback(() => {
    if (step === 1) {
      setTouchedName(true);
      setTouchedEmail(true);
      if (!(name.trim().length > 0 && emailValid)) return;
    }
    if (step === 2 && satisfaction === '') return;
    setStep((prev) => (prev < 5 ? prev + 1 : prev));
  }, [step, name, emailValid, satisfaction]);

  const goBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features,
      comments: comments.trim(),
    });
  }, [submit, name, email, satisfaction, features, comments]);

  const progressValue = (step / 5) * 100;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack gap="var(--ggui-spacing-2)">
            <Row justify="between" align="center">
              <Heading level={3}>Survey</Heading>
              <Badge variant="primary">Step {step} of 5</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" variant="default" aria-label={`Survey progress: Step ${step} of 5`} />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>About you</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  error={nameError || undefined}
                  placeholder="Enter your name"
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  error={emailError || undefined}
                  placeholder="you@example.com"
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Satisfaction rating</Heading>
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={satisfactionOptions}
                  error={satisfaction === '' ? 'Please select a rating to continue.' : undefined}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Feature interests</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant)">Select all that apply.</Text>
                <Stack gap="var(--ggui-spacing-2)">
                  {(props.featureOptions || []).length === 0 ? (
                    <Alert variant="info" title="No feature options">No features are available to select.</Alert>
                  ) : (
                    (props.featureOptions || []).map((feature) => (
                      <Checkbox
                        key={feature}
                        label={feature}
                        checked={features.includes(feature)}
                        onChange={(checked) => toggleFeature(feature, checked)}
                      />
                    ))
                  )}
                </Stack>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Additional comments</Heading>
                <TextArea
                  label="Comments (optional)"
                  value={comments}
                  onChange={setComments}
                  maxLength={maxComments}
                  showCount
                  rows={6}
                  placeholder="Share any additional feedback"
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {comments.length} / {maxComments} characters
                </Text>
              </Stack>
            )}

            {step === 5 && (
              <Box role="region" aria-labelledby="review-heading">
                <Stack gap="var(--ggui-spacing-4)">
                  <Box is="div" id="review-heading">
                    <Heading level={4}>Review your answers</Heading>
                  </Box>
                  <Card padding="var(--ggui-spacing-4)" shadow="none" border>
                    <Stack gap="var(--ggui-spacing-3)">
                      <Stack gap="var(--ggui-spacing-1)">
                        <Text weight="medium">Name</Text>
                        <Text>{name || '—'}</Text>
                      </Stack>
                      <Stack gap="var(--ggui-spacing-1)">
                        <Text weight="medium">Email</Text>
                        <Text>{email || '—'}</Text>
                      </Stack>
                      <Stack gap="var(--ggui-spacing-1)">
                        <Text weight="medium">Satisfaction</Text>
                        <Text>{satisfaction || '—'}</Text>
                      </Stack>
                      <Stack gap="var(--ggui-spacing-1)">
                        <Text weight="medium">Features</Text>
                        {(features || []).length === 0 ? <Text>None selected</Text> : <Text>{features.join(', ')}</Text>}
                      </Stack>
                      <Stack gap="var(--ggui-spacing-1)">
                        <Text weight="medium">Comments</Text>
                        <Text>{comments.trim().length > 0 ? comments : 'No comments provided'}</Text>
                      </Stack>
                    </Stack>
                  </Card>
                </Stack>
              </Box>
            )}

            <Divider margin="var(--ggui-spacing-2)" />

            <Row justify="between" align="center">
              <Button variant="outline" disabled={step === 1} onClick={goBack}>
                Back
              </Button>
              {step < 5 ? (
                <Button variant="primary" disabled={!canNext} onClick={goNext}>
                  Next
                </Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit}>
                  Submit Survey
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

