];

function normalizeTask(task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }, fallbackColumn: string): BoardTask {
  return {
    id: task.id && task.id.trim() ? task.id : `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}` ,
