      return [...prev, incoming];
    });
  }, [taskChanged.latest, todoColumnId]);

  const moveTask = useCallback((taskId: string, targetColumn: string) => {
    setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: targetColumn } : task)));
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
  }, [taskUpdate]);

  const startEditing = useCallback((taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle);
  }, []);

  const saveEdit = useCallback((taskId: string) => {
    const nextTitle = editingTitle.trim();
    if (!nextTitle) return;
    setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: nextTitle } : task)));
    setEditingTaskId(null);
    setEditingTitle('');
    taskUpdate({ action: 'edit', taskId, data: { column: 'edit:title' } });
  }, [editingTitle, taskUpdate]);

  const createTask = useCallback(() => {
    const trimmed = newTaskTitle.trim();
    if (!trimmed) return;
    const newId = `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    const created: BoardTask = {
      id: newId,
      title: trimmed,
      priority: newTaskPriority,
      assignee: 'NA',
      column: todoColumnId,
    };
    setBoardTasks((prev) => [...prev, created]);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingColumnId(null);
    taskUpdate({ action: 'create', taskId: newId, data: { column: created.column } });
  }, [newTaskTitle, newTaskPriority, todoColumnId, taskUpdate]);

  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, BoardTask[]> = {};
    (props.columns || []).forEach((column) => {
      const id = String(column?.id || '');
      if (id) grouped[id] = [];
    });
    boardTasks.forEach((task) => {
      if (!grouped[task.column]) grouped[task.column] = [];
      grouped[task.column].push(task);
    });
    return grouped;
  }, [boardTasks, props.columns]);

  const totalTasks = boardTasks.length;
  const doneColumn = (props.columns || []).find((column) => String(column?.name || '').toLowerCase() === 'done' || String(column?.id || '').toLowerCase() === 'done');
  const completedCount = boardTasks.filter((task) => task.column === String(doneColumn?.id || 'done')).length;

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" border shadow="sm">
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3}>Kanban Board</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Total Tasks: {totalTasks} • Completed: {completedCount}
              </Text>
            </Stack>
            <Badge variant="primary" size="lg">
              Live updates: {taskChanged.all.length}
            </Badge>
          </Row>
        </Card>

        {(props.columns || []).length === 0 ? (
          <Alert variant="warning" title="No columns configured">
            Please provide board columns to render the Kanban layout.
          </Alert>
        ) : (
          <Row gap="var(--ggui-spacing-4)" wrap align="start">
            {(props.columns || []).map((column) => {
              const columnId = String(column?.id || '');
              const columnName = String(column?.name || 'Unnamed');
              const columnTasks = tasksByColumn[columnId] || [];
              return (
                <Card key={columnId} padding="var(--ggui-spacing-4)" border shadow="sm">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row justify="between" align="center">
                      <Heading level={5}>{columnName}</Heading>
                      <Badge variant="default">{columnTasks.length}</Badge>
                    </Row>
                    <Divider margin="var(--ggui-spacing-1)" />

                    <Stack gap="var(--ggui-spacing-3)">
                      {columnTasks.length === 0 ? (
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                          No tasks in this column.
                        </Text>
                      ) : (
                        columnTasks.map((task) => (
                          <Card key={task.id} padding="var(--ggui-spacing-3)" border shadow="none">
                            <Stack gap="var(--ggui-spacing-2)">
                              <Row justify="between" align="start">
                                {editingTaskId === task.id ? (
                                  <Input label="Edit task title" value={editingTitle} onChange={setEditingTitle} placeholder="Task title" />
                                ) : (
                                  <Text variant="label" as={Clickable} onClick={() => startEditing(task.id, task.title)} onDoubleClick={() => startEditing(task.id, task.title)} hoverStyle={{ color: 'var(--ggui-color-primary-700)', textDecoration: 'underline' }} focusStyle={{ outline: '2px solid var(--ggui-color-primary-600)', outlineOffset: '2px', borderRadius: 'var(--ggui-shape-radius-sm)' }}>{task.title}</Text>
                                )}
                                <Button size="sm" variant="ghost" onClick={() => startEditing(task.id, task.title)}>Edit</Button>
                              </Row>

                              <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                                <Badge variant={getPriorityVariant(task.priority)}>{task.priority.toUpperCase()}</Badge>
                                <Avatar name={task.assignee} size="sm" />
                                {task.dueDate ? (
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Due: {task.dueDate}</Text>
                                ) : (
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">No due date</Text>
                                )}
                              </Row>

                              <Select
                                label="Move task"
                                value={task.column}
                                onChange={(value) => moveTask(task.id, value)}
                                options={(props.columns || []).map((c) => ({ value: String(c?.id || ''), label: String(c?.name || 'Unnamed') }))}
                              />

                              {editingTaskId === task.id && (
                                <Row gap="var(--ggui-spacing-2)">
                                  <Button size="sm" variant="primary" onClick={() => saveEdit(task.id)}>Save</Button>
                                  <Button size="sm" variant="ghost" onClick={() => { setEditingTaskId(null); setEditingTitle(''); }}>Cancel</Button>
                                </Row>
                              )}
                            </Stack>
                          </Card>
                        ))
                      )}
                    </Stack>

                    {columnId === todoColumnId ? (
                      addingColumnId === columnId ? (
                        <Card padding="var(--ggui-spacing-3)" border shadow="none">
                          <Stack gap="var(--ggui-spacing-2)">
                            <Input label="Task title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Enter task title" />
                            <Select label="Priority" value={newTaskPriority} onChange={(value) => setNewTaskPriority((value as 'low' | 'medium' | 'high') || 'medium')} options={PRIORITY_OPTIONS} />
                            <Row gap="var(--ggui-spacing-2)">
                              <Button variant="primary" size="sm" onClick={() => createTask()}>Create</Button>
                              <Button variant="ghost" size="sm" onClick={() => { setAddingColumnId(null); setNewTaskTitle(''); setNewTaskPriority('medium'); }}>Cancel</Button>
                            </Row>
                          </Stack>
                        </Card>
                      ) : (
                        <Button variant="outline" size="sm" onClick={() => setAddingColumnId(columnId)}>Add Task</Button>
                      )
                    ) : null}
                  </Stack>
                </Card>
              );
            })}
          </Row>
        )}
      </Stack>
    </Container>

  );
}

