}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [search, setSearch] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const safeElements = useMemo(() => props.elements || [], [props.elements]);

  const filteredElements = useMemo(() => {
    const query = search.trim().toLowerCase();
    if (!query) return safeElements;
    return safeElements.filter((element) => {
      const name = element.name ? element.name.toLowerCase() : '';
      const symbol = element.symbol ? element.symbol.toLowerCase() : '';
      return name.includes(query) || symbol.includes(query);
    });
  }, [safeElements, search]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    safeElements.forEach((element) => {
      if (element.category) set.add(element.category);
    });
    return Array.from(set).sort((a, b) => a.localeCompare(b));
  }, [safeElements]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) return null;
    return safeElements.find((element) => element.atomicNumber === selectedAtomicNumber) || null;
  }, [safeElements, selectedAtomicNumber]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={2}>Interactive Periodic Table</Heading>

        <Input
          label="Search elements"
          placeholder="Type name or symbol (e.g., Oxygen or O)"
          value={search}
          onChange={setSearch}
