                padding: 'var(--ggui-spacing-2)',
                background: 'var(--ggui-color-surface)',
              }}
            >
              {filteredElements.length === 0 ? (
                <Box
                  style={{ gridColumn: '1 / -1' }}
                  padding="var(--ggui-spacing-4)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Text color="var(--ggui-color-onSurfaceVariant)">No elements match your search.</Text>
                </Box>
              ) : (
                filteredElements.map((element, index) => {
                  const elementKey = `${element.atomicNumber || 'x'}-${element.symbol || 'unknown'}-${index}`;
                  const isSelected = selectedElement?.atomicNumber === element.atomicNumber;
                  return (
                    <Card
                      key={elementKey}
                      as={Clickable}
                      onClick={() => setSelectedAtomicNumber(element.atomicNumber ?? null)}
                      padding="var(--ggui-spacing-2)"
                      border
                      aria-label={`${element.name || 'Unknown element'} (${element.symbol || '?'}) atomic number ${element.atomicNumber ?? 'unknown'}` }
                      hoverStyle={{
                        outline: '2px solid var(--ggui-color-primary-300)',
                        outlineOffset: '0px',
                        background: 'var(--ggui-color-primary-50)',
                      }}
                      style={{
                        minHeight: '72px',
                        gridColumn: element.col || 'auto',
                        gridRow: element.row || 'auto',
                        position: 'relative',
                        background: getCategoryColor(element.category),
                        outline: isSelected ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outline)',
                        outlineOffset: '0px',
                      }}
                    >
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant)"
                        is="span"
                        style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)' }}
                      >
                        {element.atomicNumber ?? '-'}
                      </Text>
                      <Stack justify="center" align="center" style={{ height: '100%' }}>
                        <Text size="xl" weight="bold">{element.symbol || '?'}</Text>
                      </Stack>
                    </Card>
                  );
                })
              )}
            </Box>
          </Card>
        )}

        <Card padding="var(--ggui-spacing-4)" border>
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4}>Legend</Heading>
            <Row wrap gap="var(--ggui-spacing-2)">
              {categories.map((category) => (
                <Row key={category} align="center" gap="var(--ggui-spacing-2)">
                  <Box
                    style={{ width: '14px', height: '14px', border: '1px solid var(--ggui-color-outline)' }}
                    background={getCategoryColor(category)}
                    borderRadius="var(--ggui-shape-radius-sm)"
                  />
                  <Text variant="bodySmall">{category}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)" border>
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={4}>Element Details</Heading>
            {selectedElement ? (
              <Stack gap="var(--ggui-spacing-1)">
                <Text><Text is="span" weight="semibold">Name: </Text>{selectedElement.name || '-'}</Text>
                <Text><Text is="span" weight="semibold">Symbol: </Text>{selectedElement.symbol || '-'}</Text>
