  const maxStock = useMemo(() => (typeof props.product?.stock === 'number' && props.product.stock > 0 ? props.product.stock : 1), [props.product?.stock]);
  const [quantity, setQuantity] = useState<number>(1);

  useEffect(() => {
    setQuantity((current) => {
      if (current < 1) return 1;
      if (current > maxStock) return maxStock;
      return current;
    });
  }, [maxStock]);

  const formattedPrice = useMemo(() => {
    const numericPrice = typeof props.product?.price === 'number' ? props.product.price : 0;
    const currencySymbol = props.product?.currency ?? '$';
    return `${currencySymbol}${numericPrice.toFixed(2)}`;
  }, [props.product?.price, props.product?.currency]);

  const roundedRating = useMemo(() => {
    const rawRating = typeof props.product?.rating === 'number' ? props.product.rating : 0;
    if (rawRating < 0) return 0;
    if (rawRating > 5) return 5;
    return Math.round(rawRating);
  }, [props.product?.rating]);

  const isOutOfStock = (props.product?.stock ?? 0) <= 0;
  const isLowStock = (props.product?.stock ?? 0) > 0 && (props.product?.stock ?? 0) <= 5;

  const specificationsRows = useMemo(() => {
    if (!Array.isArray(props.product?.specifications)) return [];
    return props.product.specifications.map((item, index) => {
      if (item && typeof item === 'object') {
        const record = item as Record<string, unknown>;
        const key = typeof record.key === 'string' ? record.key : `Spec ${index + 1}`;
        const value = typeof record.value === 'string' || typeof record.value === 'number' ? String(record.value) : '—';
        return { key: `${key}-${index}`, specKey: key, specValue: value };
      }
      return { key: `spec-${index}`, specKey: `Spec ${index + 1}`, specValue: String(item ?? '—') };
    });
  }, [props.product?.specifications]);

  const reviewsList = useMemo(() => {
    if (!Array.isArray(props.product?.reviews)) return [];
    return props.product.reviews.map((item, index) => {
