      const author = typeof record.author === 'string' ? record.author : `Reviewer ${index + 1}`;
      const text = typeof record.text === 'string' ? record.text : '';
      const date = typeof record.date === 'string' ? record.date : '';
      const rating = typeof record.rating === 'number' ? Math.max(1, Math.min(5, Math.round(record.rating))) : 0;
      return {
        id: `${author}-${index}`,
        author,
        text,
        date,
        rating,
      };
    });
  }, [props.product?.reviews]);

  const increaseQuantity = useCallback(() => {
    setQuantity((current) => (current < maxStock ? current + 1 : current));
  }, [maxStock]);

  const decreaseQuantity = useCallback(() => {
    setQuantity((current) => (current > 1 ? current - 1 : current));
  }, []);

