// Place helper components here if needed
function formatTimestamp(value?: string): string {
  if (!value) return '';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return '';
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

function getMessageKey(item: { sender?: string; text?: string; timestamp?: string }, index: number): string {
  return `${item.sender ?? 'unknown'}-${item.timestamp ?? 'no-time'}-${index}`;
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag
  const [messageText, setMessageText] = useState<string>('');
  const [allMessages, setAllMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages ?? []);
  const endRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setAllMessages(props.messages ?? []);
  }, [props.messages]);

  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest as StreamMessage]);
    }
  }, [message.latest]);

  useEffect(() => {
    if (endRef.current) {
      endRef.current.scrollIntoView({ behavior: 'smooth', block: 'end' });
    }
  }, [allMessages.length, typing.latest?.active, typing.latest?.sender]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    (allMessages ?? []).forEach((item) => {
      const previous = groups[groups.length - 1];
      if (previous && previous.sender === item.sender) {
        previous.items.push(item);
      } else {
        groups.push({ sender: item.sender, items: [item] });
      }
    });
    return groups;
  }, [allMessages]);

  const typingText = useMemo(() => {
    if (!typing.latest?.active) return '';
    if (typing.latest.sender && typing.latest.sender !== props.currentUser) {
      return `${typing.latest.sender} is typing...`;
    }
    return '';
  }, [typing.latest, props.currentUser]);

  const handleSend = useCallback(() => {
    const trimmed = messageText.trim();
    if (!trimmed) return;
    const timestamp = new Date().toISOString();
    sendMessage({ text: trimmed, timestamp });
    setAllMessages((prev) => [...prev, { sender: props.currentUser, text: trimmed, timestamp }]);
    setMessageText('');
  }, [messageText, sendMessage, props.currentUser]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
