          </Row>
          {typingText ? (
            <Box margin="var(--ggui-spacing-2)">
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{typingText}</Text>
            </Box>
          ) : null}
        </Card>

        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Box
            style={{
              height: '60vh',
              overflowY: 'auto',
              background: 'var(--ggui-color-surface)',
              borderRadius: 'var(--ggui-shape-radius-md)',
              padding: 'var(--ggui-spacing-3)',
            }}
          >
            <Stack gap="var(--ggui-spacing-3)">
              {groupedMessages.length === 0 ? (
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  No messages yet.
                </Text>
              ) : null}

              {groupedMessages.map((group, groupIndex) => {
                const isOwnGroup = group.sender === props.currentUser;
                return (
                  <Stack key={`${group.sender ?? 'unknown'}-${groupIndex}`} gap="var(--ggui-spacing-1)" align={isOwnGroup ? 'end' : 'start'}>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      {group.sender ?? 'Unknown'}
                    </Text>
                    {group.items.map((item, itemIndex) => (
                      <Box
                        key={getMessageKey(item, itemIndex)}
                        background={isOwnGroup ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                        borderRadius="var(--ggui-shape-radius-lg)"
                        padding="var(--ggui-spacing-3)"
                        style={{ maxWidth: '80%' }}
                      >
                        <Stack gap="var(--ggui-spacing-1)">
                          <Text color={isOwnGroup ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurface)'}>{item.text ?? ''}</Text>
                          <Text
                            variant="caption"
                            color={isOwnGroup ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurfaceVariant)'}
                            align={isOwnGroup ? 'right' : 'left'}
                          >
                            {formatTimestamp(item.timestamp)}
                          </Text>
                        </Stack>
                      </Box>
                    ))}
                  </Stack>
                );
              })}

              {typingText ? (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{typingText}</Text>
              ) : null}
              <Box><div ref={endRef} /></Box>
            </Stack>
          </Box>
        </Card>

        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Row gap="var(--ggui-spacing-2)" align="end">
            <Box style={{ flex: 1 }}>
              <Input
                label="Message"
                placeholder="Type a message..."
                value={messageText}
                onChange={setMessageText}
                onKeyDown={(event) => {
                  if (event.key === 'Enter' && !event.shiftKey) {
                    event.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Button
              as={Clickable}
              onClick={handleSend}
              variant="primary"
              disabled={!messageText.trim()}
            >
              Send
            </Button>
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}

